import 'package:flame/components.dart';

import 'country_data.dart';

/// Available game regions.
enum GameRegion {
  world,
  usStates,
  ukCounties,
  caribbean,
  ireland,
  canadianProvinces,
  europe,
  africa,
  asia,
  latinAmerica,
  oceania,
  australia,
  france,
  germany,
  japan,
  spain,
  italy,
  brazil,
  india,
  newZealand,
}

/// Whether a region uses a flat map projection instead of the globe.
///
/// Flat-map regions show a static satellite view with the plane moving
/// across the screen, rather than the globe-centred view.
bool isRegionalFlatMap(GameRegion region) {
  switch (region) {
    case GameRegion.world:
    case GameRegion.caribbean:
    case GameRegion.europe:
    case GameRegion.africa:
    case GameRegion.asia:
    case GameRegion.latinAmerica:
    case GameRegion.oceania:
      return false;
    case GameRegion.usStates:
    case GameRegion.ukCounties:
    case GameRegion.ireland:
    case GameRegion.canadianProvinces:
    case GameRegion.australia:
    case GameRegion.france:
    case GameRegion.germany:
    case GameRegion.japan:
    case GameRegion.spain:
    case GameRegion.italy:
    case GameRegion.brazil:
    case GameRegion.india:
    case GameRegion.newZealand:
      return true;
  }
}

