  /// Map bounds for the region [minLng, minLat, maxLng, maxLat]
  List<double> get bounds {
    switch (this) {
      case GameRegion.world:
        return [-180, -85, 180, 85];
      case GameRegion.usStates:
        return [-125, 24, -66, 50];
      case GameRegion.ukCounties:
        return [-11, 49, 3, 61];
      case GameRegion.caribbean:
        return [-85, 10, -59, 28];
      case GameRegion.ireland:
        return [-11, 51, -5, 56];
      case GameRegion.canadianProvinces:
        return [-141, 42, -52, 72];
      case GameRegion.europe:
        return [-25, 34, 45, 72];
      case GameRegion.africa:
        return [-18, -35, 52, 38];
      case GameRegion.asia:
        return [25, -12, 150, 55];
      case GameRegion.latinAmerica:
        return [-118, -56, -34, 33];
      case GameRegion.oceania:
        return [110, -50, 180, 0];
      case GameRegion.australia:
        return [112, -44, 154, -10];
      case GameRegion.france:
        return [-5.5, 41, 10, 51.5];
      case GameRegion.germany:
        return [5.5, 47, 15.5, 55.5];
      case GameRegion.japan:
        return [123, 24, 146.5, 46];
      case GameRegion.spain:
        return [-10, 35.5, 5, 44.5];
      case GameRegion.italy:
        return [6, 36.5, 19, 47.5];
      case GameRegion.brazil:
        return [-74.5, -34.5, -34, 6];
      case GameRegion.india:
        return [67.5, 7.5, 98, 36];
      case GameRegion.newZealand:
        return [166, -47.5, 179, -34];
    }
  }

  /// Center point for the region
  Vector2 get center {
    final b = bounds;
    return Vector2((b[0] + b[2]) / 2, (b[1] + b[3]) / 2);
  }

  /// Required level to unlock this region
  int get requiredLevel {
    switch (this) {
      case GameRegion.world:
        return 1;
      case GameRegion.usStates:
        return 3;
      case GameRegion.canadianProvinces:
        return 4;
      case GameRegion.ukCounties:
        return 5;
      case GameRegion.europe:
        return 3;
      case GameRegion.africa:
        return 5;
      case GameRegion.asia:
        return 7;
      case GameRegion.latinAmerica:
        return 9;
      case GameRegion.oceania:
        return 11;
      case GameRegion.caribbean:
        return 7;
      case GameRegion.ireland:
        return 10;
      case GameRegion.australia:
        return 3;
      case GameRegion.france:
        return 4;
      case GameRegion.germany:
        return 6;
      case GameRegion.spain:
        return 8;
      case GameRegion.italy:
        return 8;
      case GameRegion.japan:
        return 12;
      case GameRegion.brazil:
        return 14;
      case GameRegion.india:
        return 16;
      case GameRegion.newZealand:
        return 18;
    }
  }

  /// Whether this region uses a flat map projection instead of the globe.
  bool get isFlatMap => isRegionalFlatMap(this);
}

/// Regional area shape (state, county, island, etc.)
class RegionalArea {
  const RegionalArea({
    required this.code,
    required this.name,
    required this.points,
    this.polygons,
    this.capital,
    this.population,
    this.funFact,
  });

  final String code;
  final String name;

  /// Flat list of all points (used for hit-testing, centroids, etc.)
  final List<Vector2> points;

  /// Separate polygon rings. When non-null, renderers should draw each ring
  /// as its own sub-path to avoid artefacts between disjoint polygons.
  final List<List<Vector2>>? polygons;
  final String? capital;
  final int? population;
  final String? funFact;
}

/// Regional data provider.
abstract class RegionalData {
  /// Get areas for a region
  static List<RegionalArea> getAreas(GameRegion region) {
    switch (region) {
      case GameRegion.world:
        return CountryData.countries
            .map(
              (c) => RegionalArea(
                code: c.code,
                name: c.name,
                points: c.allPoints,
                polygons: c.polygons,
                capital: c.capital,
              ),
            )
            .toList();
      case GameRegion.usStates:
        return _usStates;
      case GameRegion.ukCounties:
        return _ukCounties;
      case GameRegion.caribbean:
        return _caribbeanIslands;
      case GameRegion.ireland:
        return _irelandCounties;
      case GameRegion.canadianProvinces:
        return _canadianProvinces;
      case GameRegion.europe:
        return _countriesForCodes(_europeCodes);
      case GameRegion.africa:
        return _countriesForCodes(_africaCodes);
      case GameRegion.asia:
        return _countriesForCodes(_asiaCodes);
      case GameRegion.latinAmerica:
        return _countriesForCodes(_latinAmericaCodes);
      case GameRegion.oceania:
        return _countriesForCodes(_oceaniaCodes);
      case GameRegion.australia:
        return _australiaStates;
      case GameRegion.france:
        return _franceRegions;
      case GameRegion.germany:
        return _germanyStates;
      case GameRegion.japan:
        return _japanPrefectures;
      case GameRegion.spain:
        return _spainCommunities;
      case GameRegion.italy:
        return _italyRegions;
      case GameRegion.brazil:
        return _brazilStates;
      case GameRegion.india:
        return _indiaStates;
      case GameRegion.newZealand:
        return _newZealandRegions;
    }
  }

  static List<RegionalArea> _countriesForCodes(Set<String> codes) {
    // Honour the global exclusion list: territories the world modes filter
    // out (too obscure / flag renders as the parent country's) must not
    // resurface as playable areas in regional quizzes either.
    return CountryData.countries
        .where((c) =>
            codes.contains(c.code) &&
            !CountryData.excludedTerritories.contains(c.code))
        .map(
          (c) => RegionalArea(
            code: c.code,
            name: c.name,
            points: c.allPoints,
            polygons: c.polygons,
            capital: c.capital,
          ),
        )
        .toList();
  }

